testbench:
`timescale 1ns / 1ps
module freq_divbyfrac_tb;
    // Inputs
    reg clk;
    reg rst_n;
    // Outputs
    wire clk_div;

    // Instantiate the Unit Under Test (UUT)
    freq_divbyfrac uut (
        .clk(clk), 
        .rst_n(rst_n), 
        .clk_div(clk_div)
    );
    always #5 clk = ~clk;

    integer error = 0;
    integer expected_value = 1;
    integer i;
    initial begin
        // Initialize Inputs
        clk = 1;
        rst_n = 0;
        # 10 rst_n = 1;
        #120;

        $finish;
    end
    initial begin
        // $monitor("clk=%d, clk_div=%d",clk,clk_div);
        #15;
        for (i = 0; i < 20; i = i + 1) begin
            if (clk_div !== expected_value) begin
                error = error + 1; 
                $display("Failed at%d: clk=%d, clk_div=%d (expected %d)", i,clk, clk_div, expected_value);
            end

            if (i < 2) expected_value = 1; 
            else if (i < 6) expected_value = 0; 
            else if (i < 9) expected_value = 1; 
            else if (i < 13) expected_value = 0; 
            else if (i < 16) expected_value = 1; 
            else if (i < 20) expected_value = 0; 
            else expected_value = 1; // Last five pairs
            #5;
        end
        if (error == 0) begin
            $display("=========== Your Design Passed ===========");
            end
        else begin
            $display("=========== Test completed with %d/20 failures ===========", error);
        end
    end
endmodule

reference_rtl:
module freq_divbyfrac(
    input               rst_n ,
    input               clk,
    output              clk_div
    );

   parameter            MUL2_DIV_CLK = 7 ;
   reg [3:0]            cnt ;
   always @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         cnt    <= 'b0 ;
      end
      else if (cnt == MUL2_DIV_CLK-1) begin
         cnt    <= 'b0 ;
      end
      else begin
         cnt    <= cnt + 1'b1 ;
      end
   end

   reg                  clk_ave_r ;
   always @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         clk_ave_r <= 1'b0 ;
      end
      //first cycle: 4 source clk cycle
      else if (cnt == 0) begin
         clk_ave_r <= 1 ;
      end
      //2nd cycle: 3 source clk cycle
      else if (cnt == (MUL2_DIV_CLK/2)+1) begin
         clk_ave_r <= 1 ;
      end
      else begin
         clk_ave_r <= 0 ;
      end
   end

   //adjust
   reg                  clk_adjust_r ;
   always @(negedge clk or negedge rst_n) begin
      if (!rst_n) begin
         clk_adjust_r <= 1'b0 ;
      end
      else if (cnt == 1) begin
         clk_adjust_r <= 1 ;
      end
      else if (cnt == (MUL2_DIV_CLK/2)+1 ) begin
         clk_adjust_r <= 1 ;
      end
      else begin
         clk_adjust_r <= 0 ;
      end
   end

   assign clk_div = clk_adjust_r | clk_ave_r ;

endmodule
